@endsection @push('scripts')<script>const nav=document.getElementById('navigation-app');function updateNavigation(){['pickup','dropoff'].forEach(type=>{const link=document.getElementById('navigate-'+type);if(link)link.href=nav.value+encodeURIComponent(link.dataset.address)})}nav?.addEventListener('change',updateNavigation);updateNavigation();const permission=document.getElementById('permission-state'),secure=document.getElementById('secure-context-state');secure.textContent=window.isSecureContext?'Yes':'No — GPS may be blocked. Use HTTPS/tunnel/staging.';if(navigator.permissions){navigator.permissions.query({name:'geolocation'}).then(s=>{permission.textContent=s.state;s.onchange=()=>permission.textContent=s.state}).catch(()=>{})}document.getElementById('send-location').addEventListener('click',function(){const out=document.getElementById('location-result');if(!window.isSecureContext){out.textContent='HTTPS/secure context is required for mobile browser geolocation.';return}if(!navigator.geolocation){out.textContent='Browser geolocation is unavailable. Use a supported phone browser over HTTPS.';return}out.textContent='Requesting precise location permission…';navigator.geolocation.getCurrentPosition(async p=>{try{const r=await fetch(@json(route('worker.location-pings.store')),{method:'POST',headers:{'Content-Type':'application/json','X-CSRF-TOKEN':document.querySelector('meta[name=csrf-token]').content,'Accept':'application/json'},body:JSON.stringify({order_id:{{ $order->id }},latitude:p.coords.latitude,longitude:p.coords.longitude,accuracy_meters:p.coords.accuracy,heading:p.coords.heading,speed_mps:p.coords.speed,captured_at:new Date(p.timestamp).toISOString(),consent:true})});const d=await r.json();out.textContent=r.ok?`Real GPS ping recorded. Lat ${p.coords.latitude.toFixed(5)}, lng ${p.coords.longitude.toFixed(5)}, accuracy ${d.accuracy_meters} m, captured ${d.captured_at}.`:Object.values(d.errors||{error:d.message||'Server rejected the location ping.'}).flat().join(' ')}catch(error){out.textContent='Location was not sent because the server request failed.'}},e=>out.textContent=e.code===1?'Location permission denied. Allow precise location and try again.':e.code===3?'Location request timed out. Move outdoors and try again.':'Location was not sent: '+e.message,{enableHighAccuracy:true,timeout:15000,maximumAge:0})})</script>@endpush
